nodes.notes:
Radarr — movie library. Use for movies and films. Not for TV shows — use sonarr for TV shows.

Actions:
  search — search for a movie in the library. Use for "is Inception on Radarr", "search for The Matrix".
  calendar — upcoming movie releases. Use for "any movies coming out", "new releases this month".
  library — list all movies in your library. Use for "what movies do I have", "how many movies".
  history — recent download and import activity. Use for "what was recently downloaded", "recent activity".

---schema
{
  "action": {
    "type": "string",
    "description": "One of: calendar, search, library, history",
    "required": true
  },
  "query": {
    "type": "string",
    "description": "Movie name, e.g. Interstellar, The Matrix. For: search"
  },
  "days": {
    "type": "integer",
    "description": "Calendar lookahead days. Default 30. For: calendar"
  },
  "limit": {
    "type": "integer",
    "description": "Max items to return. Default 20. For: library, history"
  }
}

parameters.jsCode:
// Parse input and extract action + parameters
let data;
const input = $input.item.json;

if (typeof input.body === 'string') {
  data = JSON.parse(input.body);
} else if (typeof input.body === 'object') {
  data = input.body;
} else {
  data = input;
}

const action = (data.action || '').toLowerCase();
const query = data.query || '';
const days = parseInt(data.days) || 30;
const limit = parseInt(data.limit) || 20;

// For calendar, calculate date range
const start = new Date();
start.setHours(0, 0, 0, 0);
const end = new Date(start);
end.setDate(end.getDate() + days);

return [{
  json: {
    action: action,
    query: query,
    queryLower: query.toLowerCase(),
    days: days,
    limit: limit,
    start: start.toISOString().split('T')[0],
    end: end.toISOString().split('T')[0]
  }
}];

// Format calendar for voice
const movies = $input.all();
const days = $('Parse Parameters').item.json.days;

if (movies.length === 0) {
  return { message: `No movies scheduled in the next ${days} days.`, count: 0, movies: [] };
}

const formatted = movies.map(item => {
  const m = item.json;
  // Radarr uses digitalRelease, physicalRelease, or inCinemas
  const releaseDate = m.digitalRelease || m.physicalRelease || m.inCinemas;
  const date = releaseDate ? new Date(releaseDate) : null;
  const formattedDate = date ? date.toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' }) : 'TBA';

  return {
    title: m.title || 'Unknown Movie',
    year: m.year,
    releaseDate: formattedDate,
    releaseDateRaw: releaseDate,
    hasFile: m.hasFile || false,
    monitored: m.monitored || false
  };
});

formatted.sort((a, b) => {
  if (!a.releaseDateRaw) return 1;
  if (!b.releaseDateRaw) return -1;
  return new Date(a.releaseDateRaw) - new Date(b.releaseDateRaw);
});

let message = '';
if (formatted.length === 1) {
  const m = formatted[0];
  message = `One movie coming: ${m.title} on ${m.releaseDate}.`;
} else {
  message = `${formatted.length} movies in the next ${days} days. `;
  const titles = formatted.slice(0, 4).map(m => m.title);
  message += titles.join(', ');
  if (formatted.length > 4) message += `, and ${formatted.length - 4} more.`;
}

return { message, count: formatted.length, movies: formatted };

// Filter and format results
const allMovies = $input.all();
const query = $('Parse Parameters').item.json.queryLower;

const matches = allMovies.filter(item => {
  const title = (item.json.title || '').toLowerCase();
  const originalTitle = (item.json.originalTitle || '').toLowerCase();
  return title.includes(query) || originalTitle.includes(query);
});

if (matches.length === 0) {
  return {
    message: `No movies found matching "${$('Parse Parameters').item.json.query}".`,
    found: false,
    movies: []
  };
}

const movies = matches.map(item => {
  const m = item.json;
  const sizeGB = m.sizeOnDisk ? (m.sizeOnDisk / 1073741824).toFixed(1) : 0;

  return {
    title: m.title,
    year: m.year,
    hasFile: m.hasFile || false,
    sizeGB: parseFloat(sizeGB),
    quality: m.movieFile?.quality?.quality?.name || 'N/A',
    status: m.status,
    monitored: m.monitored
  };
});

let message = '';
if (movies.length === 1) {
  const m = movies[0];
  if (m.hasFile) {
    message = `Yes, you have ${m.title} (${m.year}). ${m.quality}, ${m.sizeGB} GB.`;
  } else if (m.monitored) {
    message = `${m.title} (${m.year}) is in your library but not downloaded yet. It's being monitored.`;
  } else {
    message = `${m.title} (${m.year}) is in your library but not downloaded or monitored.`;
  }
} else {
  const downloaded = movies.filter(m => m.hasFile).length;
  message = `Found ${movies.length} movies matching your search. ${downloaded} downloaded. `;
  const titles = movies.slice(0, 3).map(m => m.title);
  message += titles.join(', ');
  if (movies.length > 3) message += `, and ${movies.length - 3} more.`;
}

return { message, found: true, count: movies.length, movies };

const errorData = $input.item.json;
let errorMsg = errorData.message || errorData.error || 'Unknown error';
if (typeof errorMsg === 'object') {
  errorMsg = errorMsg.message || JSON.stringify(errorMsg);
}
errorMsg = String(errorMsg);

if (errorMsg.includes('401') || errorMsg.includes('403') || errorMsg.includes('Unauthorized')) {
  errorMsg = 'Radarr authentication failed. Check the API key in n8n.';
} else if (errorMsg.includes('ECONNREFUSED') || errorMsg.includes('ETIMEDOUT')) {
  errorMsg = 'Cannot connect to Radarr. Is it running?';
} else if (errorMsg.includes('Credential')) {
  errorMsg = 'Radarr credentials not found in n8n.';
}

return [{ json: { message: `Error with Radarr: ${errorMsg}`, error: true } }];

// Handle invalid action
const action = $input.item.json.action || 'unknown';
return {
  message: `Invalid action: "${action}". Use 'calendar', 'search', 'library', or 'history'.`,
  error: true
};

// Format library overview for voice
const allMovies = $input.all();
const limit = $('Parse Parameters').item.json.limit;

const total = allMovies.length;
const withFiles = allMovies.filter(item => item.json.hasFile).length;
const monitored = allMovies.filter(item => item.json.monitored).length;

// Sort alphabetically and limit
const sorted = allMovies
  .map(item => {
    const m = item.json;
    const sizeGB = m.sizeOnDisk ? (m.sizeOnDisk / 1073741824).toFixed(1) : 0;
    return {
      title: m.title || 'Unknown',
      year: m.year,
      quality: m.movieFile?.quality?.quality?.name || 'N/A',
      has_file: m.hasFile || false,
      monitored: m.monitored || false,
      size_gb: parseFloat(sizeGB)
    };
  })
  .sort((a, b) => a.title.localeCompare(b.title))
  .slice(0, limit);

let message = `You have ${total} movies in your library. ${withFiles} have files, ${monitored} are monitored.`;
if (sorted.length > 0) {
  const preview = sorted.slice(0, 5).map(m => `${m.title} (${m.year})`).join(', ');
  message += ` Including: ${preview}`;
  if (total > 5) message += `, and more.`;
}

return { message, count: total, with_files: withFiles, monitored, movies: sorted };

const input = $input.item.json;
const limit = $('Parse Parameters').item.json.limit;

const eventTypeMap = {
  'grabbed': 'Grabbed',
  'downloadFolderImported': 'Imported',
  'movieFileDeleted': 'Deleted',
  'downloadFailed': 'Failed',
  'movieFileRenamed': 'Renamed'
};

const records = (input.records || []).slice(0, limit);

if (records.length === 0) {
  return [{ json: { message: 'No recent history found.', count: 0, history: [] } }];
}

const history = records.map(r => {
  const title = r.movie?.title || r.sourceTitle || 'Unknown';
  const quality = r.quality?.quality?.name || 'Unknown';
  const event = eventTypeMap[r.eventType] || r.eventType || 'Unknown';
  const date = r.date ? new Date(r.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' }) : 'Unknown';
  return { title, quality, event, date };
});

const lines = history.slice(0, 5).map((h, i) => `${i + 1}. ${h.event} ${h.title} in ${h.quality}`);
let message = 'Recent activity: ' + lines.join('. ') + '.';
if (history.length > 5) message += ` And ${history.length - 5} more.`;

return [{ json: { message, count: history.length, history } }];
